import pyotp
import qrcode
import base64
import time

class TOTPAuthenticator:
    def __init__(self, issuer_name="MyMFA", account_name="user@example.com"):
        self.issuer_name = issuer_name
        self.account_name = account_name

    def generate_secret(self):
        """Generates a new base32-encoded TOTP secret."""
        return pyotp.random_base32()

    def get_provisioning_uri(self, secret, account_name=None):
        """
        Generates the provisioning URI (otpauth://) for a given secret.
        This URI can be used to generate a QR code.
        """
        if account_name is None:
            account_name = self.account_name
        return pyotp.totp.TOTP(secret).provisioning_uri(
            name=account_name,
            issuer_name=self.issuer_name
        )

    def generate_qr_code_data_url(self, secret, account_name=None):
        """
        Generates a data URL for a QR code image that can be displayed in a web browser.
        """
        uri = self.get_provisioning_uri(secret, account_name)
        img = qrcode.make(uri)
        
        # Convert PIL Image to bytes
        import io
        buf = io.BytesIO()
        img.save(buf, format="PNG")
        img_bytes = buf.getvalue()
        
        # Encode to base64
        encoded_img = base64.b64encode(img_bytes).decode('utf-8')
        return f"data:image/png;base64,{encoded_img}"

    def verify_totp(self, secret, user_totp_code, window=1):
        """
        Verifies a user-provided TOTP code against the secret.
        
        Args:
            secret (str): The base32-encoded TOTP secret.
            user_totp_code (str): The TOTP code entered by the user.
            window (int): The number of time steps to check before and after the current one.
                          A window of 1 means it checks current, previous, and next step.
                          Default is 1, which is common for robustness against clock drift.
        
        Returns:
            bool: True if the code is valid, False otherwise.
        """
        totp = pyotp.TOTP(secret)
        return totp.verify(user_totp_code, valid_window=window)

    def get_current_totp(self, secret):
        """
        Calculates and returns the current TOTP code for a given secret.
        Useful for testing or displaying the expected code.
        """
        totp = pyotp.TOTP(secret)
        return totp.now()

